// PassRate v3.3-grid-persist
const express = require('express');
const cors    = require('cors');
const fetch   = require('node-fetch');
const app = express();
const PORT = process.env.PORT || 3000;
app.use(cors()); app.use(express.json());
const OANDA = 'https://api-fxpractice.oanda.com';
app.get('/api/pricing',async(req,res)=>{const{apiKey,accountId,instruments}=req.query;if(!apiKey||!accountId||!instruments)return res.status(400).json({error:'Missing'});try{const r=await fetch(OANDA+'/v3/accounts/'+accountId+'/pricing?instruments='+instruments,{headers:{Authorization:'Bearer '+apiKey}});const d=await r.json();if(!r.ok)return res.status(r.status).json(d);res.json(d);}catch(e){res.status(502).json({error:e.message})}});
app.get('/api/candles',async(req,res)=>{const{apiKey,instrument,granularity,count}=req.query;if(!apiKey||!instrument)return res.status(400).json({error:'Missing'});try{const r=await fetch(OANDA+'/v3/instruments/'+instrument+'/candles?granularity='+(granularity||'M5')+'&count='+(count||100),{headers:{Authorization:'Bearer '+apiKey}});const d=await r.json();if(!r.ok)return res.status(r.status).json(d);res.json(d);}catch(e){res.status(502).json({error:e.message})}});
app.get('/api/account',async(req,res)=>{const{apiKey,accountId}=req.query;if(!apiKey||!accountId)return res.status(400).json({error:'Missing'});try{const r=await fetch(OANDA+'/v3/accounts/'+accountId+'/summary',{headers:{Authorization:'Bearer '+apiKey}});const d=await r.json();if(!r.ok)return res.status(r.status).json(d);res.json(d);}catch(e){res.status(502).json({error:e.message})}});
app.get('/health',(_, res)=>res.json({status:'ok',version:'v3.3-grid-persist'}));
const SIMULATOR_B64='';
const SIMULATOR_HTML=Buffer.from(SIMULATOR_B64,'base64').toString('utf8');
app.get('*',(_, res)=>{res.setHeader('Content-Type','text/html; charset=utf-8');res.send(SIMULATOR_HTML);});
app.listen(PORT,()=>console.log('PassRate v3.3-grid-persist on port '+PORT));
